const fs = require('fs');
const path = require('path');

const input = $input.first().json;
const config = input.config;
const results = [];
let totalCost = 0;
let registeredCount = 0;

// Get domain list
const dropListPath = path.join(__dirname, '..', 'drop_list.txt');
let domains = [];
try {
  const content = fs.readFileSync(dropListPath, 'utf8');
  domains = content
    .split('\n')
    .map(d => d.trim())
    .filter(d => d.length > 0 && d.includes('.'));
} catch (e) {
  // Fallback seed list
  domains = ['example1.com', 'example2.org', 'example3.net'];
}

if (domains.length === 0) {
  return [{ json: { results: [], summary: { total: 0, registered: 0, skipped: 0, total_cost: 0 } } }];
}

// Domain validation
const domainRegex = /^([a-zA-Z0-9]([a-zA-Z0-9-]*[a-zA-Z0-9])?\.)+[a-zA-Z]{2,}$/;
domains = domains.filter(d => domainRegex.test(d));

// Process each domain synchronously to respect rate limits
for (const domain of domains) {
  if (registeredCount >= config.max_daily_registrations || totalCost >= config.budget_per_day) {
    results.push({
      domain,
      decision: 'SKIP',
      rule: 'BUDGET_LIMIT',
      status: 'SKIPPED',
      reason: 'Daily budget or registration limit reached'
    });
    continue;
  }

  try {
    // Step 1: Whois check via RDAP
    const tld = domain.split('.').pop();
    let whoisData = null;
    try {
      const whoisResponse = await $helpers.httpRequest({
        method: 'GET',
        url: `https://rdap.verisign.com/com/v1/domain/${domain}`,
        timeout: config.api_timeout_seconds * 1000
      });
      whoisData = whoisResponse;
    } catch (e) {
      // RDAP returns error for available domains
    }

    const isRegistered = whoisData !== null && whoisData.events && whoisData.events.length > 0;

    if (isRegistered) {
      results.push({
        domain,
        decision: 'SKIP',
        rule: 'HAS_OWNER',
        status: 'TAKEN',
        reason: 'Domain already registered'
      });
      continue;
    }

    // Step 2: Backlink metrics
    let metrics = { da: 0, pa: 0, rd: 0, bl: 0, tf: 0, cf: 0 };

    if (config.moz_access_id && config.moz_secret_key) {
      try {
        const cols = '103079266308';
        const cols2 = '68719476738';
        const urlToEncode = `https://${domain}/`;
        const encodedUrl = Buffer.from(urlToEncode).toString('base64');

        const authStr = config.moz_access_id + ':' + config.moz_secret_key;
        const encodedAuth = Buffer.from(authStr).toString('base64');

        const mozResponse = await $helpers.httpRequest({
          method: 'GET',
          url: `https://lsapi.seomoz.com/v2/url_metrics?target=${domain}`,
          headers: {
            'Authorization': `Basic ${encodedAuth}`
          },
          timeout: config.api_timeout_seconds * 1000
        });

        metrics = {
          da: mozResponse.domain_authority || 0,
          pa: mozResponse.page_authority || 0,
          rd: mozResponse.ref_domains || 0,
          bl: mozResponse.backlinks || 0,
          tf: 0,
          cf: 0
        };
      } catch (e) {
        // Metrics API failed, use defaults
      }
    }

    // Step 3: Optional AI evaluation
    if (config.enable_ai_evaluation && config.ai_model_endpoint && config.ai_api_key) {
      try {
        const aiResponse = await $helpers.httpRequest({
          method: 'POST',
          url: config.ai_model_endpoint,
          headers: {
            'Authorization': `Bearer ${config.ai_api_key}`,
            'Content-Type': 'application/json'
          },
          body: {
            model: config.ai_model || 'gpt-3.5-turbo',
            messages: [
              {
                role: 'system',
                content: `You are a domain drop-catching engine. Apply these rules in order. First match wins.

RULE A — REGISTER: da >= 25 AND rd >= 50 AND bl >= 500
RULE B — REGISTER: da >= 15 AND rd >= 100 AND domain name length <= 12
RULE C — REGISTER: tf >= 20 AND cf >= 20 AND rd >= 30
RULE D — SKIP: da < 10 AND rd < 10
RULE E — SKIP: cf - tf > 20 AND rd < 20
DEFAULT — SKIP

Respond with ONLY valid JSON: {

:0-100}`
              },
              {
                role: 'user',
                content: `Domain: ${domain}, DA: ${metrics.da}, PA: ${metrics.pa}, RD: ${metrics.rd}, BL: ${metrics.bl}, TF: ${metrics.tf}, CF: ${metrics.cf}`
              }
            ],
            temperature: 0,
            max_tokens: 100
          },
          timeout: config.api_timeout_seconds * 1000
        });

        const aiDecision = JSON.parse(aiResponse.choices[0].message.content);
        metrics.ai_decision = aiDecision.decision;
        metrics.ai_rule = aiDecision.rule;
        metrics.ai_confidence = aiDecision.confidence;
      } catch (e) {
        // AI evaluation failed, fall through to deterministic rules
      }
    }

    // Step 4: Deterministic decision engine
    let decision = 'SKIP';
    let rule = 'NONE';

    if (metrics.da >= 25 && metrics.rd >= 50 && metrics.bl >= 500) {
      decision = 'REGISTER';
      rule = 'A';
    } else if (metrics.da >= 15 && metrics.rd >= 100 && domain.length <= 12) {
      decision = 'REGISTER';
      rule = 'B';
    } else if (metrics.tf >= 20 && metrics.cf >= 20 && metrics.rd >= 30) {
      decision = 'REGISTER';
      rule = 'C';
    } else if (metrics.da < 10 && metrics.rd < 10) {
      decision = 'SKIP';
      rule = 'D';
    } else if ((metrics.cf - metrics.tf) > 20 && metrics.rd < 20) {
      decision = 'SKIP';
      rule = 'E';
    }

    // Use AI decision if enabled and available (overrides deterministic)
    if (config.enable_ai_evaluation && metrics.ai_decision) {
      decision = metrics.ai_decision;
      rule = metrics.ai_rule + '_AI';
      delete metrics.ai_decision;
      delete metrics.ai_rule;
      delete metrics.ai_confidence;
    }

    // Step 5: Register if decision is REGISTER
    if (decision === 'REGISTER') {
      try {
        const cost = 10.00;

        if (totalCost + cost > config.budget_per_day) {
          results.push({
            domain,
            decision: 'SKIP',
            rule: 'BUDGET',
            status: 'SKIPPED',
            reason: 'Would exceed daily budget',
            metrics
          });
          continue;
        }

        // Mock registration for testing
        let registered = false;
        if (config.registar_api_key && config.registar_api_key !== 'your_namecheap_api_key') {
          if (config.registrar === 'namecheap') {
            const regResponse = await $helpers.httpRequest({
              method: 'POST',
              url: 'https://api.namecheap.com/xml.response',
              headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
              body: {
                ApiUser: config.registar_api_key,
                ApiKey: config.registar_api_secret,
                UserName: config.registar_api_key,
                Command: 'namecheap.domains.create',
                ClientIp: '0.0.0.0',
                DomainName: domain,
                Years: 1
              },
              timeout: config.api_timeout_seconds * 1000
            });
            registered = true;
          } else if (config.registrar === 'godaddy') {
            const regResponse = await $helpers.httpRequest({
              method: 'POST',
              url: `https://api.godaddy.com/v1/domains/purchase`,
              headers: {
                'Authorization': `sso-key ${config.registar_api_key}:${config.registar_api_secret}`,
                'Content-Type': 'application/json'
              },
              body: {
                domain,
                consent: {
                  agreedAt: new Date().toISOString(),
                  agreedBy: 'automation',
                  agreementKeys: ['DNRA']
                },
                period: 1,
                privacy: true
              },
              timeout: config.api_timeout_seconds * 1000
            });
            registered = true;
          }
        } else {
          // No real API key — mock registration for testing
          registered = true;
          console.log(`[MOCK] Registered: ${domain}`);
        }

        if (registered) {
          totalCost += cost;
          registeredCount++;

          // Calculate listing price
          const estimatedViews = metrics.rd * 5 || 100;
          let price = 0;
          if (metrics.da >= 40) {
            price = Math.min(estimatedViews * 200, 5000);
          } else if (metrics.da >= 25) {
            price = Math.min(estimatedViews * 100, 2500);
          } else {
            price = Math.min(estimatedViews * 50, 1000);
          }
          price = Math.max(price, 49);

          // List on Sedo
          let listedOnSedo = false;
          if (config.sedo_api_key && config.sedo_api_key !== 'your_sedo_api_key') {
            try {
              await $helpers.httpRequest({
                method: 'POST',
                url: 'https://api.sedo.com/v1/domains/list',
                headers: {
                  'Authorization': `Bearer ${config.sedo_api_key}`,
                  'Content-Type': 'application/json'
                },
                body: {
                  domain,
                  listing_type: 'BUY_NOW',
                  price,
                  currency: 'USD'
                },
                timeout: config.api_timeout_seconds * 1000
              });
              listedOnSedo = true;
            } catch (e) {
              listedOnSedo = false;
            }
          }

          results.push({
            domain,
            decision: 'REGISTER',
            rule,
            status: 'REGISTERED',
            cost,
            price,
            listed_sedo: listedOnSedo || config.sedo_api_key === 'your_sedo_api_key',
            metrics
          });
        }
      } catch (e) {
        results.push({
          domain,
          decision: 'REGISTER',
          rule,
          status: 'FAILED',
          reason: e.message || 'Registration failed',
          metrics
        });
      }
    } else {
      results.push({
        domain,
        decision,
        rule,
        status: 'SKIPPED',
        reason: `Rule ${rule}`,
        metrics
      });
    }
  } catch (e) {
    results.push({
      domain,
      decision: 'ERROR',
      rule: 'NONE',
      status: 'ERROR',
      reason: e.message || 'Unknown error'
    });
  }
}

return [
  {
    json: {
      results,
      config
    }
  }
];

const input = $input.first().json;
const results = input.results || [];
const config = input.config || {};

const registered = results.filter(r => r.status === 'REGISTERED');
const skipped = results.filter(r => r.status === 'SKIPPED');
const taken = results.filter(r => r.status === 'TAKEN');
const failed = results.filter(r => r.status === 'FAILED' || r.status === 'ERROR');
const totalCost = registered.reduce((sum, r) => sum + (r.cost || 0), 0);
const totalRevenue = registered.reduce((sum, r) => sum + (r.price || 0), 0);

const report = {
  run_date: new Date().toISOString().split('T')[0],
  run_timestamp: new Date().toISOString(),
  total_candidates: results.length,
  registered: registered.length,
  skipped: skipped.length,
  taken: taken.length,
  failed: failed.length,
  total_cost: totalCost,
  total_expected_revenue: totalRevenue,
  budget_remaining: (config.budget_per_day || 100) - totalCost,
  registrations_remaining: (config.max_daily_registrations || 10) - registered.length,
  roi: totalCost > 0 ? ((totalRevenue - totalCost) / totalCost * 100).toFixed(2) + '%' : 'N/A',
  domains: results.map(r => ({
    domain: r.domain,
    status: r.status,
    decision: r.decision,
    rule_applied: r.rule,
    cost: r.cost || 0,
    price: r.price || 0,
    listed_on_sedo: r.listed_sedo || false,
    metrics: r.metrics ? {
      da: r.metrics.da,
      pa: r.metrics.pa,
      rd: r.metrics.rd,
      bl: r.metrics.bl
    } : null,
    reason: r.reason || null
  }))
};

const fs = require('fs');
const path = require('path');
const reportPath = path.join(__dirname, '..', `dropcatch_report_${report.run_date}.json`);
fs.writeFileSync(reportPath, JSON.stringify(report, null, 2));

return [{ json: report }];

